def show_file(path, max_chars=12000):
    p=Path(path)
    print(f'===== {path} exists={p.exists()} size={p.stat().st_size if p.exists() else None} =====')
    if p.exists():
        txt=p.read_text(errors='replace')
        print(txt[:max_chars])
        if len(txt)>max_chars:
            print(f'...TRUNCATED {len(txt)-max_chars} chars...')

